<!doctype html><html lang="pt-BR"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Admin Campanha | Cristian Pelo Autismo</title><link rel="stylesheet" href="../../style.css"></head><body>
<header class="topbar"><div class="container nav"><a class="brand" href="../"><img src="../../assets/img/logo.webp" alt="Logo"><span>Admin Campanha</span></a><nav class="menu"><a href="../">Campanha</a><a href="../../">Site</a></nav></div></header>
<main class="section"><div class="container"><div class="section-head"><span class="eyebrow">Painel protegido</span><h2>Visão dos apoios recebidos</h2><p class="lead">Acompanhe total de apoios, cidades, bairros/regiões, contatos e exporte a base para CSV.</p></div><div id="loginPanel" class="panel" style="max-width:520px"><h3>Entrar no painel</h3><form id="login" class="form"><input id="pass" type="password" placeholder="Senha do administrador" required><button class="btn" type="submit">Entrar</button></form><p id="msg" style="font-weight:900;color:#b42318"></p></div><div id="dash" style="display:none"><div class="admin-grid"><div class="admin-card"><strong id="total">0</strong><span>Total de apoios</span></div><div class="admin-card"><strong id="cities">0</strong><span>Cidades</span></div><div class="admin-card"><strong id="districts">0</strong><span>Bairros/regiões</span></div><div class="admin-card"><strong id="last">-</strong><span>Último apoio</span></div></div><div class="grid-2" style="margin-top:26px"><div class="map-panel"><h3 style="margin-top:0">Apoios por cidade</h3><div id="barsCity"></div></div><div class="map-panel"><h3 style="margin-top:0">Apoios por bairro/região</h3><div id="barsDistrict"></div></div></div><div class="panel" style="margin-top:26px"><div style="display:flex;gap:12px;justify-content:space-between;align-items:center;flex-wrap:wrap"><h3 style="margin:0">Lista de apoios</h3><button class="btn secondary" onclick="downloadCSV()">Exportar CSV</button></div><div style="overflow:auto;margin-top:18px"><table class="admin-table"><thead><tr><th>Data</th><th>Nome</th><th>WhatsApp</th><th>E-mail</th><th>Cidade</th><th>Bairro</th><th>Tipo</th><th>Mensagem</th></tr></thead><tbody id="rows"></tbody></table></div></div></div></div></main>
<script>
let items=[];function safe(v){return String(v??'').replace(/[&<>"]/g,s=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;'}[s]))}function csv(v){return '"'+String(v??'').replaceAll('"','""')+'"'}function downloadCSV(){const head=['data','nome','whatsapp','email','cidade','bairro','tipo','mensagem'];const lines=[head.join(',')].concat(items.map(i=>head.map(h=>csv(i[h])).join(',')));const blob=new Blob([lines.join('\n')],{type:'text/csv;charset=utf-8'});const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download='apoios-cristian-autismo.csv';a.click()}function renderBars(elId,list){const box=document.getElementById(elId);if(!list||!list.length){box.innerHTML='<p style="color:#526b7d">Sem dados ainda.</p>';return}const max=Math.max(...list.map(i=>i.total));box.innerHTML=list.slice(0,10).map(i=>`<div class="bar-row"><strong>${safe(i.nome)}</strong><div class="bar"><span style="width:${Math.max(8,(i.total/max)*100)}%"></span></div><b>${i.total}</b></div>`).join('')}
login.addEventListener('submit',async e=>{e.preventDefault();msg.textContent='';const pass=encodeURIComponent(pass.value);const r=await fetch('../api.php?action=list&pass='+pass);const j=await r.json();if(!j.ok){msg.textContent='Senha inválida ou sem acesso.';return}items=j.items||[];loginPanel.style.display='none';dash.style.display='block';total.textContent=items.length;cities.textContent=new Set(items.map(i=>i.cidade).filter(Boolean)).size;districts.textContent=new Set(items.map(i=>i.bairro).filter(Boolean)).size;last.textContent=items[items.length-1]?.cidade||'-';renderBars('barsCity',j.stats?.byCity||[]);renderBars('barsDistrict',j.stats?.byDistrict||[]);rows.innerHTML=items.slice().reverse().map(i=>`<tr><td>${new Date(i.data).toLocaleString('pt-BR')}</td><td>${safe(i.nome)}</td><td>${safe(i.whatsapp)}</td><td>${safe(i.email)}</td><td>${safe(i.cidade)}</td><td>${safe(i.bairro)}</td><td>${safe(i.tipo)}</td><td>${safe(i.mensagem)}</td></tr>`).join('')});
</script></body></html>
